public double getPct(Object v) {
    return getPct((Comparable<?>) v);
}

additional_testcases.testcase:
public void testPctWithNullValue() {
    f.addValue(oneL);
    f.addValue(twoL);
    f.addValue(oneI);
    f.addValue(twoI);
    assertEquals("null pct", 0.0, f.getPct((Object) null), tolerance);
}

public void testPctWithSingleValue() {
    f.addValue(oneL);
    assertEquals("single value pct", 1.0, f.getPct((Object) oneL), tolerance);
}

public void testPctWithNonExistentValue() {
    f.addValue(oneL);
    f.addValue(twoL);
    assertEquals("non-existent value pct", 0.0, f.getPct((Object) Integer.valueOf(99)), tolerance);
}
